                tasksError: tasksState.tasksError,
                loadVideos: videosActions.loadVideos,
                loadTasks: tasksActions.loadTasks,
                openVideoDetails: videosActions.openVideoDetails,
                deleteVideo: videosActions.deleteVideo,
